import { GoogleGenAI, Type } from "@google/genai";
import { ProductData, ProgramPlan } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const PROMPT_SYSTEM = `
You are a top-tier TV Shopping Director for "Yihe Shopping" (宜和购物). 
Your goal is to generate a high-converting, professional TV shopping program plan.
The tone should be enthusiastic, trustworthy, and urgent (fear of missing out).
Everything must be in Simplified Chinese (zh-CN).
`;

export const generateProgramPlan = async (data: ProductData): Promise<ProgramPlan> => {
  const prompt = `
    Product: ${data.name}
    Category: ${data.category}
    Price: ${data.price}
    Target Audience: ${data.targetAudience}
    Key Features: ${data.keyFeatures}
    Promotion/Deal: ${data.promotion}

    Create a TV shopping program plan including:
    1. A catchy program title.
    2. A strong opening hook (30 seconds).
    3. 3-4 Key Selling Points (Feature -> Benefit -> How to demo it).
    4. A dialogue script between two hosts (Main Host and Expert/Guest).
    5. Common customer objections and how to handle them.
    6. Visual suggestions for the screen (graphics, props).
  `;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: prompt,
    config: {
      systemInstruction: PROMPT_SYSTEM,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          catchyTitle: { type: Type.STRING, description: "Exciting title for the segment" },
          hook: { type: Type.STRING, description: "Opening speech to grab attention" },
          sellingPoints: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                feature: { type: Type.STRING },
                benefit: { type: Type.STRING },
                demonstration: { type: Type.STRING, description: "How to show this on camera" }
              }
            }
          },
          script: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                speaker: { type: Type.STRING, description: "Name/Role of speaker" },
                text: { type: Type.STRING },
                emotion: { type: Type.STRING, description: "Tone of voice" }
              }
            }
          },
          objections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                concern: { type: Type.STRING },
                rebuttal: { type: Type.STRING }
              }
            }
          },
          visualSuggestions: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["catchyTitle", "hook", "sellingPoints", "script", "objections", "visualSuggestions"]
      }
    }
  });

  if (!response.text) {
    throw new Error("No text returned from Gemini");
  }

  return JSON.parse(response.text) as ProgramPlan;
};

export const generateConceptImage = async (productName: string, visualDesc: string): Promise<string> => {
  const prompt = `
    Professional studio photography for TV shopping channel "Yihe Shopping".
    Product: ${productName}.
    Context: ${visualDesc}.
    High quality, bright lighting, 4k, advertising style.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-image",
    contents: prompt,
    config: {
        // No thinking needed for image generation
    }
  });

  // Iterate to find image part
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image generated");
};

import React, { useState } from 'react';
