        // No thinking needed for image generation
    }
  });

  // Iterate to find image part
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image generated");
};

import React, { useState } from 'react';
import { ProgramPlan, ProductData, BoardAsset } from '../types';
import { FileText, MessageSquare, AlertCircle, Image as ImageIcon, ChevronRight, Video, ClipboardList, Layers, Monitor, Printer } from 'lucide-react';
