import React, { useState } from 'react';
import { ProgramPlan, ProductData, BoardAsset } from '../types';
import { FileText, MessageSquare, AlertCircle, Image as ImageIcon, ChevronRight, Video, ClipboardList, Layers, Monitor, Printer, Upload, X, Sparkles, Download } from 'lucide-react';
import { generateConceptImage } from '../services/geminiService';

interface Props {
  plan: ProgramPlan;
  productName: string;
  onReset: () => void;
}

const PlanDisplay: React.FC<Props> = ({ plan, productName, onReset }) => {
  const [activeTab, setActiveTab] = useState<'strategy' | 'script' | 'materials' | 'visuals'>('materials');
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const [imageContext, setImageContext] = useState<string>("");

  // New state for custom image generation
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [customReq, setCustomReq] = useState<string>("");

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
        const reader = new FileReader();
        reader.onloadend = () => {
            setUploadedImage(reader.result as string);
        };
        reader.readAsDataURL(file);
    }
  };

  const handleGenerateImage = async (prompt: string, isText: boolean = false) => {
    if (isGeneratingImage) return;

    // Switch to visuals tab so user can see the loading state/result
    setActiveTab('visuals');

    setIsGeneratingImage(true);
    setImageContext(prompt);
    try {
      const imageBase64 = await generateConceptImage(
        productName, 
        prompt, 
        isText, 
        uploadedImage || undefined, 
        customReq
      );
      setGeneratedImage(imageBase64);
    } catch (e) {
      console.error(e);
      alert("图片生成失败，请重试。");
    } finally {
      setIsGeneratingImage(false);
    }
  };

  const renderMaterialBadge = (type: string) => {
    switch (type) {
      case 'A3 KT Board':
        return <span className="px-2 py-0.5 rounded text-xs font-bold bg-blue-100 text-blue-800 border border-blue-200">A3 KT板</span>;
      case 'A4 Copperplate':
        return <span className="px-2 py-0.5 rounded text-xs font-bold bg-orange-100 text-orange-800 border border-orange-200">A4 铜板纸</span>;
      default:
        return <span className="px-2 py-0.5 rounded text-xs font-bold bg-slate-100 text-slate-800 border border-slate-200">A4 普通纸</span>;
