import { GoogleGenAI, Type } from "@google/genai";
import { ProductData, ProgramPlan } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const PROMPT_SYSTEM = `
You are a top-tier TV Shopping Director for "Yihe Shopping" (宜和购物). 
Your goal is to generate a high-converting, professional TV shopping program plan.
The tone should be enthusiastic, trustworthy, and urgent (fear of missing out).
Everything must be in Simplified Chinese (zh-CN).

CRITICAL MATERIAL STANDARDS FOR YIHE SHOPPING:
1. Videos: Must be 16:9 HD. Needs to be submitted 3 days prior to "Yihe Editing Group".
2. Background: 16:9 LED screen. Logo & Product must be centered.
3. KT Boards (A3 Size): Used for Brand Intro, Awards/Patents, Partners/Distributors, Selling Points (Ingredients/Origin - NO EFFICACY CLAIMS).
4. Handheld Cards (A4 Copperplate/Tongban Paper): Used for Price Comparison (Online/Offline), Customer Misconceptions (Big Title).
5. Documents (A4 Regular Paper): Test Reports, Import Declarations (must be original color prints).
`;

export const generateProgramPlan = async (data: ProductData): Promise<ProgramPlan> => {
  const prompt = `
    Product: ${data.name}
    Category: ${data.category}
    Price: ${data.price}
    Target Audience: ${data.targetAudience}
    Key Features: ${data.keyFeatures}
    Promotion/Deal: ${data.promotion}

    Create a TV shopping program plan including:
    1. A catchy program title.
    2. A strong opening hook (30 seconds).
    3. 3-4 Key Selling Points.
    4. A dialogue script.
    5. Objection handling.
    6. Visual suggestions.
    7. A DETAILED MATERIAL PREPARATION LIST based on Yihe Standards.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: prompt,
    config: {
      systemInstruction: PROMPT_SYSTEM,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          catchyTitle: { type: Type.STRING },
          hook: { type: Type.STRING },
          sellingPoints: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                feature: { type: Type.STRING },
                benefit: { type: Type.STRING },
                demonstration: { type: Type.STRING }
              }
            }
          },
          script: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                speaker: { type: Type.STRING },
                text: { type: Type.STRING },
                emotion: { type: Type.STRING }
              }
            }
          },
          objections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                concern: { type: Type.STRING },
                rebuttal: { type: Type.STRING }
              }
            }
          },
          visualSuggestions: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          materialGuide: {
            type: Type.OBJECT,
            properties: {
              videos: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    content: { type: Type.STRING, description: "What is in the video" },
                    requirement: { type: Type.STRING, description: "Format/Deadline" }
                  }
                }
              },
              ledBackground: { type: Type.STRING, description: "Description of the LED background image" },
              ktBoards: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    title: { type: Type.STRING },
                    content: { type: Type.STRING, description: "Key bullets/info on the board" },
                    format: { type: Type.STRING, enum: ['A3 KT Board'] }
                  }
                }
              },
              handheldCards: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    title: { type: Type.STRING },
                    content: { type: Type.STRING },
                    format: { type: Type.STRING, enum: ['A4 Copperplate'] }
                  }
                }
              },
              documents: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              },
              props: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["videos", "ledBackground", "ktBoards", "handheldCards", "documents", "props"]
          }
        },
        required: ["catchyTitle", "hook", "sellingPoints", "script", "objections", "visualSuggestions", "materialGuide"]
      }
    }
  });

  if (!response.text) {
    throw new Error("No text returned from Gemini");
  }

  return JSON.parse(response.text) as ProgramPlan;
};

export const generateConceptImage = async (
  productName: string, 
  visualDesc: string, 
  isTextHeavy: boolean = false,
  referenceImage?: string,
  customReq?: string
): Promise<string> => {
  let promptText = `
    Professional TV shopping studio photography for Yihe Shopping (宜和购物).
    Product Name: ${productName}.
    Scene Context: ${visualDesc}.
    ${customReq ? `User Custom Requirements: ${customReq}` : ''}

    Style Guidelines:
    - 8K Resolution, Ultra HD, highly detailed textures.
    - Commercial Advertising Photography standard.
    - Bright, professional studio lighting.
    - 16:9 Cinematic Aspect Ratio composition.
  `;

  if (isTextHeavy) {
    promptText += `
      \n*** MANDATORY TEXT RENDERING INSTRUCTION ***
      The image is a professional presentation board (KT board) or handheld card used in a TV studio.

      TEXT REQUIREMENT:
      The image MUST display the following Simplified Chinese text clearly and correctly: "${visualDesc}"

      STRICT RULES:
      1. RENDER THE TEXT EXACTLY AS WRITTEN ABOVE.
      2. NO SPELLING ERRORS. Characters must be perfect Simplified Chinese.
      3. Typography: Bold, Professional, Sans-serif (like Heiti).
      4. Contrast: High contrast (e.g., Black text on White/Yellow background, or White text on Red/Blue background).
      5. Layout: The text must be the central focus of the image, occupying a significant portion of the board.
      6. Do not include any other nonsensical text.
    `;
  }

  const parts: any[] = [{ text: promptText }];

  if (referenceImage) {
      // Extract base64 data if it contains the prefix
      const base64Data = referenceImage.includes(',') 
        ? referenceImage.split(',')[1] 
        : referenceImage;

      // Attempt to determine mime type, default to jpeg if generic
      let mimeType = 'image/jpeg';
      if (referenceImage.includes('data:image/png')) mimeType = 'image/png';
      if (referenceImage.includes('data:image/webp')) mimeType = 'image/webp';

      parts.unshift({
          inlineData: {
              data: base64Data,
              mimeType: mimeType
          }
      });
  }

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-image",
    contents: { parts },
    config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
    }
  });

  // Iterate to find image part
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image generated");
};

import React, { useState, useEffect } from 'react';
import { ProductData } from '../types';
import { ArrowRight, Package, Tag, Users, Sparkles, Receipt, History, Clock, Trash2, ChevronRight, RefreshCw } from 'lucide-react';

interface Props {
  onSubmit: (data: ProductData) => void;
  isLoading: boolean;
}

interface HistoryItem {
  id: number;
  timestamp: number;
  data: ProductData;
}

const HISTORY_KEY = 'yihe_history_v1';
const EXPIRY_DAYS = 30;
const EXPIRY_MS = EXPIRY_DAYS * 24 * 60 * 60 * 1000;

const InputForm: React.FC<Props> = ({ onSubmit, isLoading }) => {
  const [formData, setFormData] = useState<ProductData>({
    name: '',
    category: '',
    price: '',
    targetAudience: '',
    keyFeatures: '',
    promotion: ''
  });

  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  // Load and clean history on mount
  useEffect(() => {
    try {
      const saved = localStorage.getItem(HISTORY_KEY);
      if (saved) {
        const parsed: HistoryItem[] = JSON.parse(saved);
        const now = Date.now();

        // Filter items older than 30 days
        const validHistory = parsed.filter(item => (now - item.timestamp) < EXPIRY_MS);

        setHistory(validHistory);

        // Update local storage if items were expired and removed
        if (validHistory.length !== parsed.length) {
          localStorage.setItem(HISTORY_KEY, JSON.stringify(validHistory));
        }
      }
    } catch (e) {
      console.error("Failed to load history", e);
      // If corrupted, clear it
      localStorage.removeItem(HISTORY_KEY);
    }
  }, []);

  const saveToHistory = (data: ProductData) => {
    // Prevent saving duplicates at the top of the list
    if (history.length > 0 && JSON.stringify(history[0].data) === JSON.stringify(data)) {
        return;
    }

    const newItem: HistoryItem = {
      id: Date.now(),
      timestamp: Date.now(),
      data: { ...data } // Create a copy
    };

    const newHistory = [newItem, ...history].slice(0, 50); // Keep last 50 items max
    setHistory(newHistory);
    localStorage.setItem(HISTORY_KEY, JSON.stringify(newHistory));
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    saveToHistory(formData);
    onSubmit(formData);
  };

  const loadHistoryItem = (item: HistoryItem) => {
    setFormData(item.data);
    setShowHistory(false);
  };

  const deleteHistoryItem = (e: React.MouseEvent, id: number) => {
    e.stopPropagation();
    const updated = history.filter(item => item.id !== id);
    setHistory(updated);
    localStorage.setItem(HISTORY_KEY, JSON.stringify(updated));
  };

  const clearAllHistory = () => {
      if(window.confirm("确定要清空所有历史记录吗？此操作无法撤销。")) {
          setHistory([]);
          localStorage.removeItem(HISTORY_KEY);
      }
  };

  const formatDate = (ts: number) => {
    return new Date(ts).toLocaleString('zh-CN', {
        month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit'
    });
  };

  return (
    <div className="w-full max-w-3xl mx-auto bg-white rounded-2xl shadow-xl overflow-hidden border border-slate-100 relative transition-all">
      <div className="bg-gradient-to-r from-red-600 to-rose-500 p-6 text-white flex justify-between items-center sticky top-0 z-20">
        <div>
            <h2 className="text-2xl font-bold flex items-center gap-2">
            <Package className="w-6 h-6" />
            产品资料录入
            </h2>
            <p className="text-red-100 mt-1 text-sm">输入产品信息，AI将为您生成宜和购物风格的节目策划案。</p>
        </div>
        <button 
            onClick={() => setShowHistory(!showHistory)}
            className="flex items-center gap-1.5 bg-white/20 hover:bg-white/30 active:bg-white/40 text-white px-3 py-1.5 rounded-lg text-xs font-bold transition backdrop-blur-sm border border-white/20"
            title="查看历史记录"
        >
            <History className="w-4 h-4" />
            {showHistory ? '返回录入' : '历史记录'}
        </button>
      </div>

      {showHistory ? (
        <div className="h-[600px] overflow-y-auto bg-slate-50 relative animate-fade-in">
             <div className="sticky top-0 bg-slate-100/90 backdrop-blur-sm border-b border-slate-200 p-3 flex justify-between items-center z-10">
                 <span className="text-xs font-bold text-slate-500 flex items-center gap-1">
                    <Clock className="w-3 h-3" /> 本地记录保存30天
                 </span>
                 {history.length > 0 && (
                     <button 
                        onClick={clearAllHistory}
                        className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1 px-2 py-1 rounded hover:bg-red-50 transition"
                     >
                        <Trash2 className="w-3 h-3" /> 清空所有
                     </button>
                 )}
             </div>

             {history.length === 0 ? (
                 <div className="flex flex-col items-center justify-center h-4/5 text-slate-400">
                     <History className="w-16 h-16 mb-4 opacity-20" />
                     <p className="text-sm font-medium">暂无历史记录</p>
                     <p className="text-xs mt-2 opacity-60">提交的表单将自动保存在这里</p>
                     <button onClick={() => setShowHistory(false)} className="mt-6 text-rose-600 hover:underline text-sm font-bold">
                        去录入第一个产品
                     </button>
                 </div>
             ) : (
                 <div className="divide-y divide-slate-200">
                     {history.map(item => (
                         <div 
                            key={item.id} 
