import { GoogleGenAI, Type } from "@google/genai";
import { ProductData, ProgramPlan } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const PROMPT_SYSTEM = `
You are a top-tier TV Shopping Director for "Yihe Shopping" (宜和购物). 
Your goal is to generate a high-converting, professional TV shopping program plan.
The tone should be enthusiastic, trustworthy, and urgent (fear of missing out).
Everything must be in Simplified Chinese (zh-CN).

CRITICAL MATERIAL STANDARDS FOR YIHE SHOPPING:
1. Videos: Must be 16:9 HD. Needs to be submitted 3 days prior to "Yihe Editing Group".
2. Background: 16:9 LED screen. Logo & Product must be centered.
3. KT Boards (A3 Size): Used for Brand Intro, Awards/Patents, Partners/Distributors, Selling Points (Ingredients/Origin - NO EFFICACY CLAIMS).
4. Handheld Cards (A4 Copperplate/Tongban Paper): Used for Price Comparison (Online/Offline), Customer Misconceptions (Big Title).
5. Documents (A4 Regular Paper): Test Reports, Import Declarations (must be original color prints).
`;

export const generateProgramPlan = async (data: ProductData): Promise<ProgramPlan> => {
  const prompt = `
    Product: ${data.name}
    Category: ${data.category}
    Price: ${data.price}
    Target Audience: ${data.targetAudience}
    Key Features: ${data.keyFeatures}
    Promotion/Deal: ${data.promotion}

    Create a TV shopping program plan including:
    1. A catchy program title.
    2. A strong opening hook (30 seconds).
    3. 3-4 Key Selling Points.
    4. A dialogue script.
    5. Objection handling.
    6. Visual suggestions.
    7. A DETAILED MATERIAL PREPARATION LIST based on Yihe Standards.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: prompt,
    config: {
      systemInstruction: PROMPT_SYSTEM,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          catchyTitle: { type: Type.STRING },
          hook: { type: Type.STRING },
          sellingPoints: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                feature: { type: Type.STRING },
                benefit: { type: Type.STRING },
                demonstration: { type: Type.STRING }
              }
            }
          },
          script: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                speaker: { type: Type.STRING },
                text: { type: Type.STRING },
                emotion: { type: Type.STRING }
              }
            }
          },
          objections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                concern: { type: Type.STRING },
                rebuttal: { type: Type.STRING }
              }
            }
          },
          visualSuggestions: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          materialGuide: {
            type: Type.OBJECT,
            properties: {
              videos: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    content: { type: Type.STRING, description: "What is in the video" },
                    requirement: { type: Type.STRING, description: "Format/Deadline" }
                  }
                }
              },
              ledBackground: { type: Type.STRING, description: "Description of the LED background image" },
              ktBoards: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    title: { type: Type.STRING },
                    content: { type: Type.STRING, description: "Key bullets/info on the board" },
                    format: { type: Type.STRING, enum: ['A3 KT Board'] }
                  }
                }
              },
              handheldCards: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    title: { type: Type.STRING },
                    content: { type: Type.STRING },
                    format: { type: Type.STRING, enum: ['A4 Copperplate'] }
                  }
                }
              },
              documents: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              },
              props: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            },
            required: ["videos", "ledBackground", "ktBoards", "handheldCards", "documents", "props"]
          }
        },
        required: ["catchyTitle", "hook", "sellingPoints", "script", "objections", "visualSuggestions", "materialGuide"]
      }
    }
  });

  if (!response.text) {
    throw new Error("No text returned from Gemini");
  }

  return JSON.parse(response.text) as ProgramPlan;
};

export const generateConceptImage = async (
  productName: string, 
  visualDesc: string, 
  isTextHeavy: boolean = false,
  referenceImage?: string,
  customReq?: string
): Promise<string> => {
  // Artistic Direction Prompt for High-Quality Commercial Poster
  let promptText = `
    High-end commercial photography poster for Yihe Shopping (宜和购物).
    Subject: ${productName}.
    Specific Scene: ${visualDesc}.
    ${customReq ? `Custom Nuances: ${customReq}` : ''}

    COMPOSITION & LAYOUT RULES (STRICT 16:9):
    1. TOP AREA (Upper 1/3rd): MUST be a clean, minimalist empty space (blank wall or soft bokeh) specifically reserved for placing a large headline "XXXXXX" and sub-headline "xxxxxx". Keep it uncluttered and high-contrast.
    2. FOREGROUND: Artistic arrangement of raw ingredients, natural materials, or product components related to the selling points.
    3. MIDGROUND LEFT: Core product elements or iconic features associated with ${productName}.
    4. MIDGROUND RIGHT: The actual product packaging (based on reference image if provided). 
    5. BACKGROUND: A minimalist wall with a subtle texture and a single wooden-frame window.

    LIGHTING & MOOD:
    - WARM Tones: Golden hour, cozy, trustworthy, and sophisticated.
    - Tyndall Effect: Soft but visible sunlight beams (crepuscular rays) streaming diagonally through the window.
    - Sharp Shadows: Realistic window frame shadows cast onto the wall and floor.
    - Quality: 8K resolution, Ultra-HD, cinematic depth of field, high-end advertising photography standard.
  `;

  if (isTextHeavy) {
    promptText += `
      \n*** MANDATORY TEXT RENDERING INSTRUCTION ***
      This is a STUDIO PRESENTATION BOARD.
      TEXT TO RENDER: "${visualDesc}"
      STRICT RULES: Render text in perfect Simplified Chinese. Bold, high-contrast, professional typography. Center-focused on the board.
    `;
  }

  const parts: any[] = [{ text: promptText }];

  if (referenceImage) {
      const base64Data = referenceImage.includes(',') 
        ? referenceImage.split(',')[1] 
        : referenceImage;

      let mimeType = 'image/jpeg';
      if (referenceImage.includes('data:image/png')) mimeType = 'image/png';
      if (referenceImage.includes('data:image/webp')) mimeType = 'image/webp';

      parts.unshift({
          inlineData: {
              data: base64Data,
              mimeType: mimeType
          }
      });
  }

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-image",
    contents: { parts },
    config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image generated");
};

