import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateCommercialPoster = async (
  productName: string, 
  referenceImage?: string,
  customReq?: string
): Promise<string> => {
  // Artistic Direction Prompt for High-Quality Commercial Poster
  let promptText = `
    Professional high-end commercial photography poster for: ${productName}.
    ${customReq ? `Specific product selling points/elements: ${customReq}` : ''}

    COMPOSITION & LAYOUT (STRICT 16:9):
    1. TOP AREA (Upper 1/3rd): MUST be a clean, minimalist empty space (solid background or soft wall texture) reserved for placing a large headline "XXXXXX" and sub-headline "xxxxxx".
    2. FOREGROUND: Artistic arrangement of raw ingredients and natural elements associated with the product's attributes.
    3. MIDGROUND LEFT: Iconic product-related features or hero elements.
    4. MIDGROUND RIGHT: The actual product packaging. 
       *** CRITICAL BRANDING INTEGRITY RULE ***: 
       - If a reference image is provided, you MUST reconstruct the packaging with HIGH FIDELITY.
       - The TEXT, LOGOS, and TYPOGRAPHY on the packaging MUST be sharp, clear, and perfectly legible.
       - DO NOT warp, blur, or deform the text on the packaging. Maintain the original branding colors and proportions exactly as seen in the reference image.
    5. BACKGROUND: A minimalist, solid-colored wall. The color must harmonize perfectly with the product's packaging.

    LIGHTING & ATMOSPHERE:
    - Warm Natural Light: Golden hour vibes, creating a cozy and nostalgic mood.
    - Window Shadow Effect: Clear, sharp window frame shadows cast onto the wall and floor (Tyndall effect/crepuscular rays). 
    - CRITICAL: DO NOT SHOW THE WINDOW FRAME OR GLASS ITSELF. Only show the light and shadows coming from it.
    - Style: High-end advertising photography, 8K resolution, sharp details, cinematic depth of field.
  `;

  const parts: any[] = [{ text: promptText }];

  if (referenceImage) {
      const base64Data = referenceImage.includes(',') 
        ? referenceImage.split(',')[1] 
        : referenceImage;

      let mimeType = 'image/jpeg';
      if (referenceImage.includes('data:image/png')) mimeType = 'image/png';
      if (referenceImage.includes('data:image/webp')) mimeType = 'image/webp';

      parts.unshift({
          inlineData: {
              data: base64Data,
              mimeType: mimeType
          }
      });
  }

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-image",
    contents: { parts },
    config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Image generation failed");
};

